import Foundation

// Creating sets
var primeNumbers: Set = [2, 3, 5, 7, 11]
let evenNumbers: Set = [2, 4, 6, 8, 10]

// Adding and removing
primeNumbers.insert(13)
primeNumbers.insert(2)  // Already exists, no change
primeNumbers.remove(3)
print("Primes: \(primeNumbers.sorted())")

// Membership test
let number = 7
if primeNumbers.contains(number) {
    print("\(number) is prime!")
}

// Iterating (order not guaranteed)
print("All primes:", terminator: " ")
for prime in primeNumbers.sorted() {
    print(prime, terminator: " ")
}
print()

// Converting between array and set
let arrayWithDupes = [1, 2, 3, 2, 1]
let uniqueSet = Set(arrayWithDupes)
let uniqueArray = Array(uniqueSet)
print("Unique: \(uniqueArray.sorted())")
